import{_ as e,o as r,c as o,ae as t}from"./chunks/framework.Co1PSFSm.js";const p=JSON.parse('{"title":"关于我","description":"","frontmatter":{},"headers":[],"relativePath":"blog/关于我.md","filePath":"blog/关于我.md","lastUpdated":1778838363000}'),l={name:"blog/关于我.md"};function i(h,a,n,s,c,d){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to &quot;关于我&quot;">​</a></h1><h2 id="个人简介" tabindex="-1">个人简介 <a class="header-anchor" href="#个人简介" aria-label="Permalink to &quot;个人简介&quot;">​</a></h2><p>当过小兵，做过管理；敲过代码，写过文档；进过大厂，蹲过作坊。身经百战，一切都是沉淀，关注我，希望我的分享对你有所帮助！</p><p>我一直热衷于探索技术的可能性，特别是前端开发和Web应用领域。在多年的从业经历中，我经历了各种不同类型项目的锤炼，从小型创业公司的敏捷开发到大型企业的复杂系统建设，这些经历让我积累了丰富的实践经验。</p><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><ul><li><a href="https://www.xiaohongshu.com/user/profile/610e50bd00000000010088fd" target="_blank" rel="noreferrer">小红书主页</a></li><li><a href="https://github.com/codemyhappy" target="_blank" rel="noreferrer">GitHub主页</a></li><li><a href="https://blog.csdn.net/qq_21197033" target="_blank" rel="noreferrer">CSDN主页</a></li><li><a href="https://codemyhappy.github.io/" target="_blank" rel="noreferrer">个人博客</a></li></ul><h2 id="博客简介" tabindex="-1">博客简介 <a class="header-anchor" href="#博客简介" aria-label="Permalink to &quot;博客简介&quot;">​</a></h2><p>专注前端、专注互联网、分享原创的技术博客。</p><p>我的博客是我多年学习和实践的心得总结，涵盖了前端技术、互联网思考以及软件开发的最佳实践。在这里，我会分享最新的技术趋势解读、实用的开发技巧以及项目实战经验。</p><h2 id="个人项目作品" tabindex="-1">个人项目作品 <a class="header-anchor" href="#个人项目作品" aria-label="Permalink to &quot;个人项目作品&quot;">​</a></h2><p>以下是我在个人时间里开发的一些有趣项目：</p><h3 id="微信小游戏《别踩白块》" tabindex="-1">微信小游戏《别踩白块》 <a class="header-anchor" href="#微信小游戏《别踩白块》" aria-label="Permalink to &quot;微信小游戏《别踩白块》&quot;">​</a></h3><p>一款经典的休闲小游戏，考验玩家的反应速度和节奏感。使用微信小程序技术开发，界面简洁，玩法上瘾。</p><blockquote><p>提示：此处需要添加项目截图</p></blockquote><h3 id="vscode插件《blog-publisher-for-all》" tabindex="-1">VSCode插件《blog-publisher-for-all》 <a class="header-anchor" href="#vscode插件《blog-publisher-for-all》" aria-label="Permalink to &quot;VSCode插件《blog-publisher-for-all》&quot;">​</a></h3><p>一款强大的Markdown多平台发布工具，支持一键发布到多个博客平台。解决了技术写作者需要多平台同步内容的痛点。</p><blockquote><p>提示：此处需要添加插件界面截图</p></blockquote><h3 id="_2d渲染引擎-ycc-js" tabindex="-1">2D渲染引擎：ycc.js <a class="header-anchor" href="#_2d渲染引擎-ycc-js" aria-label="Permalink to &quot;2D渲染引擎：ycc.js&quot;">​</a></h3><p>一个轻量级的2D图形渲染引擎，适用于游戏开发和图形应用。该引擎具有高性能、易用性和可扩展性的特点。</p><blockquote><p>提示：此处需要添加引擎演示图</p></blockquote><h3 id="本地服务管理工具《minebook-hot-server》" tabindex="-1">本地服务管理工具《minebook-hot-server》 <a class="header-anchor" href="#本地服务管理工具《minebook-hot-server》" aria-label="Permalink to &quot;本地服务管理工具《minebook-hot-server》&quot;">​</a></h3><p>便捷的本地服务管理工具，简化开发过程中的服务器启动和管理流程，特别适合前端开发者的日常使用。</p><blockquote><p>提示：此处需要添加工具界面截图</p></blockquote><h2 id="技术专长" tabindex="-1">技术专长 <a class="header-anchor" href="#技术专长" aria-label="Permalink to &quot;技术专长&quot;">​</a></h2><ul><li><strong>前端技术</strong>: JavaScript, Vue, React, CSS, HTML, Webpack</li><li><strong>后端技术</strong>: Node.js, Python, 数据接口设计</li><li><strong>移动开发</strong>: 微信小程序, Hybrid应用</li><li><strong>工具开发</strong>: VSCode插件, 开发效率工具</li><li><strong>项目管理</strong>: 敏捷开发, 团队协作, 流程优化</li></ul><h2 id="学习与分享" tabindex="-1">学习与分享 <a class="header-anchor" href="#学习与分享" aria-label="Permalink to &quot;学习与分享&quot;">​</a></h2><p>我相信技术的价值在于分享和传播，所以我会持续在我的博客上更新技术文章和项目经验。如果你觉得我的内容对你有帮助，请关注我的各个社交媒体账号，一起交流技术心得！</p>',27)])])}const u=e(l,[["render",i]]);export{p as __pageData,u as default};
